import java.io.IOException;
import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;

public class XSSFixedCode {

    public void processInput(HttpServletRequest request, HttpServletResponse response) throws IOException {
        String userInput = request.getParameter("input");

        // Sanitize and encode user input to prevent XSS
        String sanitizedUserInput = sanitizeInput(userInput);

        String output = "Hello, " + sanitizedUserInput + "!";

        response.getWriter().write("<p>" + output + "</p>");
    }

    private String sanitizeInput(String userInput) {
        // Implement proper input sanitization here
        // You can use libraries like OWASP Java Encoder to encode user input
        // Example using OWASP Java Encoder:
        return org.owasp.encoder.Encode.forHtml(userInput);
    }
}

